class SORTracker {
private:
    int queryCount;
    struct Location {
        string name;
        int score;
    };
    struct CompareLocations {
        bool operator()(const Location& a, const Location& b) const {
            if (a.score != b.score) return a.score > b.score;
            return a.name < b.name;
        }
    };
    std::multiset<Location, CompareLocations> topLocations;
    std::multiset<Location, std::greater<Location>> bottomLocations;

public:
    SORTracker() : queryCount(0) {}

    void add(string name, int score) {
        Location newLocation = {name, score};
        topLocations.insert(newLocation);
        if (topLocations.size() > queryCount + 1) {
            auto last = *topLocations.rbegin();
            topLocations.erase(last);
            bottomLocations.insert(last);
        }
    }

    string get() {
        queryCount++;
        if (!bottomLocations.empty() && CompareLocations()(*topLocations.rbegin(), *bottomLocations.begin())) {
            auto temp = *bottomLocations.begin();
            bottomLocations.erase(temp);
            topLocations.insert(temp);
            temp = *topLocations.rbegin();
            topLocations.erase(temp);
            bottomLocations.insert(temp);
        }
        return topLocations.rbegin()->name;
    }
};

